const source = $('Normalize Event').item.json;
const trackerRow = $json || {};
const clean = (value) => String(value ?? '').trim();
const hasTrackerRow = Object.keys(trackerRow).length > 0;
const titleToMatch = clean(source.fileBaseName || String(source.fileName || '').replace(/\.[^/.]+$/, ''));
const languageCodeMap = {
  german: 'de',
  deutsch: 'de',
  de: 'de',
  english: 'en',
  englisch: 'en',
  en: 'en'
};
const normalizeSlot = (value) => {
  if (typeof value === 'number' && Number.isFinite(value)) {
    const totalMinutes = Math.round(value * 24 * 60) % (24 * 60);
    const hour = Math.floor(totalMinutes / 60);
    const minute = totalMinutes % 60;
    return String(hour).padStart(2, '0') + ':' + String(minute).padStart(2, '0');
  }
  const raw = clean(value);
  const match = raw.match(/^(\d{1,2}):(\d{2})$/);
  if (!match) return '';
  const hour = Number(match[1]);
  const minute = Number(match[2]);
  if (!Number.isInteger(hour) || !Number.isInteger(minute) || hour < 0 || hour > 23 || minute < 0 || minute > 59) return '';
  return String(hour).padStart(2, '0') + ':' + String(minute).padStart(2, '0');
};
const currentBerlinSlot = new Intl.DateTimeFormat('en-GB', {
  timeZone: 'Europe/Berlin',
  hour: '2-digit',
  minute: '2-digit',
  hour12: false,
}).format(new Date());

if (!hasTrackerRow) {
  return [{ json: { ...source, trackerRowFound: 'false', status: 'Skipped - No Tracker Row', reason: `No tracker row found where Video Title matches uploaded file name '${titleToMatch}'.`, logTimestamp: new Date().toISOString(), uploadReadyFlag: 'false', currentBerlinSlot } }];
}

const trackerStatus = clean(trackerRow['Status']);
const trackerStatusLower = trackerStatus.toLowerCase();
const title = clean(trackerRow['Video Title']);
const description = clean(trackerRow['Video Description']);
const tags = clean(trackerRow['Youtube Tags']);
const privacyInput = clean(trackerRow['Privacy Status']).toLowerCase();
const privacy = ['private', 'public', 'unlisted'].includes(privacyInput) ? privacyInput : 'public';
const madeForKidsRaw = clean(trackerRow['Made For Kids']).toLowerCase();
const madeForKids = madeForKidsRaw === 'true';
const regionCode = clean(trackerRow['Region Code']) || clean(source.youtubeRegionCode) || 'DE';
const categoryName = clean(trackerRow['Category Name']) || clean(source.youtubeCategoryName);
const languageName = clean(trackerRow['Language Name']) || clean(source.youtubeLanguageName) || 'German';
const scheduleTime = normalizeSlot(trackerRow['Schedule Time']);
const scheduleTimeDisplay = scheduleTime.replace(/^0(?=\d:)/, '');
const youtubeDefaultLanguageCode = languageCodeMap[languageName.toLowerCase()] || languageName.toLowerCase() || 'de';
const basePayload = {
  ...source,
  trackerFileName: clean(trackerRow['File Name']) || clean(source.fileName),
  trackerRowNumber: Number(trackerRow['row_number'] || 0),
  trackerStatusInput: trackerStatus,
  youtubeTitle: title,
  youtubeDescription: description,
  youtubeTags: tags,
  youtubePrivacyStatus: privacy,
  youtubeMadeForKidsBoolean: madeForKids,
  youtubeRegionCode: regionCode,
  youtubeCategoryId: clean(source.youtubeCategoryId),
  youtubeCategoryName: categoryName,
  youtubeLanguageName: languageName,
  youtubeDefaultLanguageCode,
  youtubeChannelName: clean(source.youtubeChannelName),
  youtubeChannelId: clean(source.youtubeChannelId),
  scheduleTime: scheduleTimeDisplay,
  currentBerlinSlot,
  publishAt: source.detectedAt,
};

if (trackerStatusLower === 'scheduled') {
  return [{ json: { ...basePayload, trackerRowFound: 'false', status: 'Scheduled', reason: `Tracker row for '${title}' is already marked Scheduled.`, logTimestamp: new Date().toISOString(), uploadReadyFlag: 'false' } }];
}

if (!title) {
  return [{ json: { ...basePayload, trackerRowFound: 'true', status: 'Failed - Metadata Missing', reason: `Tracker row for '${titleToMatch}' is missing required field: Video Title.`, logTimestamp: new Date().toISOString(), uploadReadyFlag: 'false' } }];
}

if (!scheduleTime) {
  return [{ json: { ...basePayload, trackerRowFound: 'false', status: 'Pending', reason: `Schedule Time is blank or invalid for '${title}'. Row ignored until a valid slot is selected.`, logTimestamp: new Date().toISOString(), uploadReadyFlag: 'false' } }];
}

if (scheduleTime !== currentBerlinSlot) {
  return [{ json: { ...basePayload, trackerRowFound: 'false', status: 'Pending', reason: `Schedule Time ${scheduleTime} does not match current Berlin slot ${currentBerlinSlot}.`, logTimestamp: new Date().toISOString(), uploadReadyFlag: 'false' } }];
}

return [{ json: { ...basePayload, trackerRowFound: 'true', status: 'Ready', reason: `Tracker row found and ready for the ${scheduleTime} Berlin slot.`, logTimestamp: new Date().toISOString(), uploadReadyFlag: 'true', youtubeTitle: title.slice(0, 100) } }];

const payload = $input.first().json;
const source = $('Evaluate Video').first().json;
const youtubeVideoId = payload.id || payload.videoId || payload.uploadId || payload.video?.id || '';
const youtubeVideoUrl = youtubeVideoId ? `https://www.youtube.com/watch?v=${youtubeVideoId}` : '';
return [{ json: { ...source, status: 'Scheduled', reason: 'Uploaded to YouTube successfully.', youtubeVideoId, youtubeVideoUrl, logTimestamp: new Date().toISOString() }, binary: $('Evaluate Video').first().binary }];

return $input.all()
  .filter((item) => item.json.uploadReadyFlag === 'true' && item.json.status !== 'Scheduled')
  .sort((a, b) => {
    const aRow = Number(a.json.trackerRowNumber || Number.MAX_SAFE_INTEGER);
    const bRow = Number(b.json.trackerRowNumber || Number.MAX_SAFE_INTEGER);
    if (aRow !== bRow) return aRow - bRow;
    return String(a.json.youtubeTitle || '').localeCompare(String(b.json.youtubeTitle || ''));
  });

const fileItems = $('Execute If MIME Type=video/mp4').all();
const descItems = $input.all();

if (fileItems.length !== descItems.length) {
  throw new Error(
    `Item count mismatch: file node has ${fileItems.length} items, description node has ${descItems.length} items`
  );
}

return fileItems.map((fileItem, i) => ({
  json: {
    fileName: fileItem.json.name,
    videoTitle: fileItem.json.name
      .replace(/\.[^/.]+$/, "")
      .replace(/\s+/g, " ")
      .trim(),
    videoDescription: descItems[i].json?.['Video Description'],
    status: "Ready"
  }
}));

const files = $input.first().json.files || [];
return files
  .filter((file) => file?.id && file?.name && file.mimeType !== 'application/vnd.google-apps.folder')
  .map((file) => ({ json: file }));

